1	export interface Customer {
2	  yearsWithMHPCO: number;
3	  previousContracts?: number;
4	}
5	
6	export interface Item {
7	  type: string;
8	  material?: string;
9	  enchantment?: number;
10	  cursed?: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const COMPONENT_TYPES = ["rune", "moonstone"];
26	const COMPONENTS_PER_BLOCK = 3;
27	const COMPONENT_BLOCK_BASE = 60;
28	const CURSE_SURCHARGE_RATE = 0.5;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	const LOYALTY_YEARS_THRESHOLD = 2;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const FOLLOW_UP_CONTRACTS_THRESHOLD = 1;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	export function quote(customer: Customer, items: Item[]): number {
37	  const percentageSurcharge = (rate: number, applies: (item: Item) => boolean): number =>
38	    items.filter(applies).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
39	
40	  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
41	  // A block of exactly COMPONENTS_PER_BLOCK alike components (same type) replaces their summed base with COMPONENT_BLOCK_BASE.
42	  const blockAdjustment = COMPONENT_TYPES.reduce((adjustment, componentType) => {
43	    const count = items.filter((item) => item.type === componentType).length;
44	    const replacement = COMPONENT_BLOCK_BASE - COMPONENTS_PER_BLOCK * BASE_PREMIUMS[componentType];
45	    return count === COMPONENTS_PER_BLOCK ? adjustment + replacement : adjustment;
46	  }, 0);
47	  const curseSurcharge = percentageSurcharge(CURSE_SURCHARGE_RATE, (item) => item.cursed === true);
48	  const highEnchantmentSurcharge = percentageSurcharge(
49	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
50	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
51	  );
52	  const adjustedBase = baseSum + blockAdjustment;
53	  const proportionalDiscount = (rate: number, qualifies: boolean): number => (qualifies ? adjustedBase * rate : 0);
54	  const firstInsurance = adjustedBase * FIRST_INSURANCE_RATE;
55	  const loyaltyDiscount = proportionalDiscount(LOYALTY_DISCOUNT_RATE, customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD);
56	  const followUpDiscount = proportionalDiscount(FOLLOW_UP_DISCOUNT_RATE, (customer.previousContracts ?? 0) >= FOLLOW_UP_CONTRACTS_THRESHOLD);
57	  return Math.ceil(adjustedBase + curseSurcharge + highEnchantmentSurcharge + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
58	}
